head.script:
scwin.processFlag = "";
scwin.E_MSG_ERR_001 = "전표번호가  (@) 존재 합니다. 수정 삭제 할 수 없습니다.";
scwin.rd_billgb_flag = "retrieve";

scwin.hid_kcomcd = "DBEX";
scwin.txt_countRow = "";
scwin.txa_pchsGoodsPatternCd = "";
scwin.txa_vatYn = "";
scwin.hid_commNm = "DBEX";
scwin.hid_acctDeptCd = "";
scwin.hid_acctDeptNm = "";
scwin.hid_intendDt = "";
scwin.hid_pchsPicNo = "";
scwin.hid_pchsPicNm = "";
scwin.dtl_sellVatNo = "";
scwin.dtl_offsetVatNo = "";

scwin.vCurDate = "";
scwin.kcomcd = "DBEX";
scwin.seaair = "S";
scwin.iogb = "O";
scwin.mblno = "";
scwin.mhno = "";
scwin.blno = "";
scwin.prtnGrpNo = "";
scwin.pchsClntNo = "";

scwin.onpageload = async function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");

    scwin.params = $c.data.getParameter();
    if (scwin.params != null) {
        if (scwin.params["kcomcd"] != null) scwin.kcomcd = scwin.params["kcomcd"];
        if (scwin.params["seaair"] != null) scwin.seaair = scwin.params["seaair"];
        if (scwin.params["iogb"] != null) scwin.iogb = scwin.params["iogb"];
        if (scwin.params["mblno"] != null) scwin.mblno = scwin.params["mblno"];
        if (scwin.params["mhno"] != null) scwin.mhno = scwin.params["mhno"];
        if (scwin.params["blno"] != null) scwin.blno = scwin.params["blno"];
        if (scwin.params["prtnGrpNo"] != null) scwin.prtnGrpNo = scwin.params["prtnGrpNo"];
        if (scwin.params["pchsClntNo"] != null) scwin.pchsClntNo = scwin.params["pchsClntNo"];
    }

    scwin.hid_kcomcd = scwin.kcomcd;
    ds_search.set("kcomcd", scwin.hid_kcomcd);
    ds_searchFreight.set("kcomcd", scwin.hid_kcomcd);
    ds_searchFreight.set("locPtnCls", "1");

    scwin.f_Set("INIT");
    scwin.f_DefaultValue();
    scwin.processFlag = "INIT";

    cnd_ed_mblno.setFocus();
};

scwin.onUdcCompleted = async function() {
};

scwin.f_DefaultValue = async function() {
    scwin.hid_kcomcd = scwin.kcomcd;
    acb_seaair.setValue(scwin.seaair);
    acb_iogb.setValue(scwin.iogb);
    cnd_ed_mblno.setValue(scwin.mblno);
    cnd_ed_blno.setValue(scwin.blno);
    cnd_ed_prtnGrpNo.setValue(scwin.prtnGrpNo);
    cnd_ed_pchsClntNo.setValue(scwin.pchsClntNo);

    if (cnd_ed_mblno.getValue() != "") {
        scwin.f_MhnoLoading("M", cnd_ed_mblno.getValue());
    }

    if (cnd_ed_blno.getValue() != "") {
        scwin.f_MhnoLoading("H", cnd_ed_blno.getValue());
    }

    acb_exgb.setValue(scwin.mhno);
};

scwin.f_Set = async function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Cancel, btn_Save, btn_Delete]);
            scwin.f_DisablePopUpObj();
            break;
        case "RETRIEVE":
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            if (scwin.processFlag == "RETRIEVE") {
                $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
                $c.gus.cfEnableBtnOnly([btn_Update, btn_Delete]);
            } else {
                $c.gus.cfDisableBtnOnly([btn_Cancel, btn_Update, btn_Save, btn_Delete]);
                $c.gus.cfEnableBtnOnly([btn_Create]);
            }
            break;
        case "CANCEL":
            scwin.f_Set("RETRIEVE");
            break;
        case "CREATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);
            break;
        case "UPDATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);
            break;
        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;
        case "DELETE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;
    }
};

scwin.f_EnablePopUpObj = async function() {
    $c.gus.cfEnableObjects([ica_pchsIntendDt, udc_pchsPic]);
};

scwin.f_DisablePopUpObj = async function() {
    $c.gus.cfDisableObjects([ica_pchsIntendDt, udc_pchsPic]);
};

scwin.f_selectTabMenu = async function(idx) {
    switch (idx) {
        case 0:
            break;
        case 1:
            break;
        case 2:
            break;
    }
};

scwin.f_Retrieve = async function() {
    if (cnd_ed_mblno.getValue().trim() == "" && cnd_ed_blno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Master or House B/L"]);
        cnd_ed_mblno.setFocus();
        return;
    }

    if (acb_exgb.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Console No"]);
        return;
    }

    ds_paymentInvoiceList.removeAll();
    ds_purchaseCerti.removeAll();
    ds_purchaseCertiDetail.removeAll();

    ds_search.set("kcomcd", scwin.hid_kcomcd);
    ds_search.set("seaair", acb_seaair.getValue());
    ds_search.set("iogb", acb_iogb.getValue());
    ds_search.set("mblno", cnd_ed_mblno.getValue());
    ds_search.set("blno", cnd_ed_blno.getValue());
    ds_search.set("mhno", acb_exgb.getValue());

    ds_search.set("prtnGrpNo", cnd_ed_prtnGrpNo.getValue());
    ds_search.set("pchsClntNo", cnd_ed_pchsClntNo.getValue());
    ds_search.set("pchsClntNm", cnd_txt_pchsClntNm.getValue());
    ds_search.set("dept", cnd_ed_dept.getValue());
    ds_search.set("deptnm", cnd_txt_deptnm.getValue());

    await $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = async function(e) {
    let rowcnt = ds_paymentInvoiceList.getRowCount();
    if (rowcnt == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.processFlag = "INIT";
        scwin.f_Set("INIT");
    } else {
        rd_billgb.setValue("1");
        scwin.rd_billgb_flag = "OnSelChange";
        scwin.f_RetrieveCommon();
        scwin.rd_billgb_flag = "retrieve";
    }
};

scwin.sbm_retrieve_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_RetrieveCommon = async function() {
    ds_purchaseCerti.removeAll();
    ds_purchaseCertiDetail.removeAll();

    let row = ds_paymentInvoiceList.getRowPosition();
    if (row < 0) return;

    let kcomcd = ds_paymentInvoiceList.getCellData(row, "kcomcd");
    let seaair = ds_paymentInvoiceList.getCellData(row, "seaair");
    let iogb = ds_paymentInvoiceList.getCellData(row, "iogb");
    let mblno = ds_paymentInvoiceList.getCellData(row, "mblno");
    let blno = ds_paymentInvoiceList.getCellData(row, "blno");
    let mhno = ds_paymentInvoiceList.getCellData(row, "mhno");

    let certiNo = ds_paymentInvoiceList.getCellData(row, "certiNo");
    let prtnGrpNo = ds_paymentInvoiceList.getCellData(row, "prtnGrpNo");
    let pchsClntNo = ds_paymentInvoiceList.getCellData(row, "pchsClntNo");
    let pchsClntNm = ds_paymentInvoiceList.getCellData(row, "pchsClntNm");
    let vatYn = ds_paymentInvoiceList.getCellData(row, "vatYn");

    let slipNo = ds_paymentInvoiceList.getCellData(row, "slipNo");
    let odrNo = ds_paymentInvoiceList.getCellData(row, "odrNo");

    if ((blno != "" || mblno != "") && pchsClntNo != "") {
        ds_searchFreight.set("kcomcd", kcomcd);
        ds_searchFreight.set("seaair", seaair);
        ds_searchFreight.set("iogb", iogb);
        ds_searchFreight.set("mblno", mblno);
        ds_searchFreight.set("blno", blno);
        ds_searchFreight.set("mhno", mhno);

        ds_searchFreight.set("certiNo", certiNo);
        ds_searchFreight.set("prtnGrpNo", prtnGrpNo);
        ds_searchFreight.set("bilgClntNo", pchsClntNo);
        ds_searchFreight.set("bilgClntNm", pchsClntNm);

        ds_searchFreight.set("odrNo", odrNo);
        ds_searchFreight.set("slipNo", slipNo);
        await $c.sbm.execute(sbm_retrieveCommon);
    }
};

scwin.sbm_retrieveCommon_submitdone = async function(e) {
    let rowcntCerti = ds_purchaseCerti.getRowCount();
    let rowcntDetail = ds_purchaseCertiDetail.getRowCount();

    if (rowcntCerti == 0 && rowcntDetail == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.processFlag = "INIT";
        scwin.f_Set("INIT");
    }

    if (rowcntCerti > 0) {
        for (let i = 0; i < rowcntCerti; i++) {
            if (ds_purchaseCerti.getCellData(i, "chk") == "F") {
                ds_purchaseCerti.setCellData(i, "chk", "T");
                ds_purchaseCerti.setCellData(i, "pchsAmt", 0);
                ds_purchaseCerti.setCellData(i, "pchsAmtFcrc", 0);
                ds_purchaseCerti.setCellData(i, "vat", 0);
            }
        }
    }
    ica_pchsIntendDt.setValue(scwin.hid_intendDt);
    ed_pchsPicNo.setValue(scwin.hid_pchsPicNo);
    txt_pchsPicNm.setValue(scwin.hid_pchsPicNm);

    if (rowcntDetail > 0) {
        scwin.hid_commNm = ds_purchaseCertiDetail.getCellData(0, "commNm");
        for (let i = 0; i < rowcntDetail; i++) {
            if (ds_purchaseCertiDetail.getCellData(i, "chk") == "F") {
                ds_purchaseCertiDetail.setCellData(i, "chk", "T");
            }
        }

        let mblnoVal = cnd_ed_mblno.getValue().trim();
        if (scwin.rd_billgb_flag == "retrieve") {
            if ((acb_seaair.getValue() == "S" && acb_iogb.getValue() == "I") ||
                (acb_seaair.getValue() == "S" && acb_iogb.getValue() == "O" && mblnoVal.substring(1, 2) == "B")) {
                let detailRow = ds_purchaseCertiDetail.getRowPosition();
                if (detailRow >= 0 && ds_purchaseCertiDetail.getCellData(detailRow, "certiNo") == "") {
                    let cr = ds_purchaseCertiDetail.getRowCount();
                    if (cr > 0) {
                        for (let i = 0; i < cr; i++) {
                            if (ds_purchaseCertiDetail.getCellData(i, "crcCd").trim() != "KRW") {
                                ds_purchaseCertiDetail.setCellData(i, "crcCd", "KRW");
                                ds_purchaseCertiDetail.setCellData(i, "exRate", 0);
                                ds_purchaseCertiDetail.setCellData(i, "pchsAmtFcrc", 0);
                                ds_purchaseCertiDetail.setCellData(i, "spplyAmtFcrc", 0);
                                ds_purchaseCertiDetail.setCellData(i, "pchsInscrpAmtFcrc", 0);
                            }
                        }
                    }
                    rd_billgb.setValue("2");
                }
            }
        }
    }
};

scwin.sbm_retrieveCommon_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.btn_Create_onclick = async function(e) {
    scwin.f_Create();
};

scwin.f_Create = async function() {
    scwin.f_Set("CREATE");
    scwin.f_billgbSetting();
    ica_pchsIntendDt.setFocus();
    ica_pchsIntendDt.setValue(scwin.vCurDate);
};

scwin.btn_Update_onclick = async function(e) {
    scwin.f_Update();
};

scwin.f_Update = async function() {
    scwin.f_Set("UPDATE");
    ica_pchsIntendDt.setFocus();
};

scwin.btn_Cancel_onclick = async function(e) {
    scwin.f_Undo();
};

scwin.f_Undo = async function() {
    let row = ds_paymentInvoiceList.getRowPosition();
    if (row >= 0) {
        ds_paymentInvoiceList.undoRow(row);
    }
    ds_purchaseCerti.removeAll();
    ds_purchaseCertiDetail.removeAll();
    scwin.f_Set("CANCEL");
};

scwin.btn_Save_onclick = async function(e) {
    scwin.f_Save();
};

scwin.f_Save = async function() {
    let row = ds_paymentInvoiceList.getRowPosition();
    if (row >= 0 && ds_paymentInvoiceList.getCellData(row, "slipNo") != "") {
        await $c.gus.cfAlertMsg(scwin.E_MSG_ERR_001, [ds_paymentInvoiceList.getCellData(row, "slipNo")]);
        return;
    }

    if (ds_purchaseCerti.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, ["Invoice"]);
        return false;
    }

    if (ds_purchaseCertiDetail.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, ["Invoice"]);
        return false;
    }

    if (ds_paymentInvoiceList.isUpdated() == false || ds_purchaseCerti.isUpdated() == false) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["Invoice"]);
        return false;
    }

    if (rd_billgb.getValue() == "2") {
        for (let i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
            ds_purchaseCerti.setCellData(i, "crcCd", "KRW");
        }
    } else {
        let cnt = 0;
        for (let i = 0; i < ds_purchaseCertiDetail.getRowCount(); i++) {
            if (ds_purchaseCertiDetail.getCellData(i, "crcCd") != "KRW") {
                cnt++;
            }
        }
        if (cnt == 0) {
            for (let j = 0; j < ds_purchaseCerti.getRowCount(); j++) {
                ds_purchaseCerti.setCellData(j, "crcCd", "KRW");
            }
        }
    }

    if (!scwin.f_AcctCdCheck()) {
        return false;
    }

    if (await scwin.f_ReqFieldChk()) {
        let chk = await $c.win.confirm(E_MSG_CM_CRM_001);
        if (chk) {
            await $c.sbm.execute(sbm_save);
            scwin.processFlag = "RETRIEVE";
            scwin.f_Set("RETRIEVE");
        }
    }
};

scwin.sbm_save_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.f_Retrieve();
};

scwin.sbm_save_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.dataSetDebug = async function(dataList, isDebug) {
    if (isDebug == true) {
        let obj = dataList;
        let str = "[[[[" + obj.getID() + "]]]]]\n";
        for (let dsRow = 0; dsRow < obj.getRowCount(); dsRow++) {
            let colInfos = obj.getColumnIDs();
            for (let dsCol = 0; dsCol < colInfos.length; dsCol++) {
                str += "[" + colInfos[dsCol] + "] " + obj.getCellData(dsRow, colInfos[dsCol]) + ", ";
            }
            str += "\n\n";
        }
        alert(str);
    }
};

scwin.btn_Delete_onclick = async function(e) {
    scwin.f_Delete();
};

scwin.f_Delete = async function() {
    let row = ds_paymentInvoiceList.getRowPosition();
    if (row >= 0 && ds_paymentInvoiceList.getCellData(row, "slipNo") != "") {
        await $c.gus.cfAlertMsg(scwin.E_MSG_ERR_001, [ds_paymentInvoiceList.getCellData(row, "slipNo")]);
        return;
    }
    let chk = await $c.win.confirm(E_MSG_CM_CRM_004);
    if (chk) {
        let cf = ds_purchaseCerti.getRowCount();
        for (let i = cf - 1; i >= 0; i--) {
            if (ds_purchaseCerti.getCellData(i, "chk") == "T") {
                ds_purchaseCerti.removeRow(i);
            }
        }
        await $c.sbm.execute(sbm_save);
    }
};

scwin.f_ReqFieldChk = async function() {
    let chk = await $c.gus.cfValidate([oDetailInfo]);
    if (chk == false) {
        return false;
    }
    return true;
};

scwin.f_SlipPopUp = async function() {
    if (ds_paymentInvoiceList.isUpdated()) {
        await $c.gus.cfAlertMsg(MSG_FS_WRN_010);
        return;
    }

    let cf = ds_purchaseCerti.getRowCount();
    for (let i = 0; i < cf; i++) {
        if (ds_purchaseCerti.getCellData(i, "chk") == "T") {
            if (ds_purchaseCerti.getCellData(i, "prtnGrpNo") != "") {
                $c.gus.cfCopyDataSet(ds_purchaseCerti, ds_certiCommonDs, "copyHeader=yes");
                ds_certiCommonDs.setCellData(0, "receptClsCd", "02");

                let pram = {};
                pram.ds_certiCommonDs = ds_certiCommonDs;
                pram.commNm = scwin.hid_commNm;

                let returnValue = await $c.win.openPopup("/ui/ds/fs/pchs/fs_202_06_03p.xml", {
                    width: 630,
                    height: 700,
                    modal: true,
                    data: pram
                });

                if (returnValue != null) {
                    if (returnValue[0] != undefined) {
                        scwin.dtl_sellVatNo = returnValue[0];
                    }
                    if (returnValue[1] == "TRUE") {
                        scwin.f_Retrieve();
                    }
                }
            } else {
                await $c.gus.cfAlertMsg(MSG_FS_WRN_002);
                return;
            }
        }
    }
};

scwin.f_PopUp = async function(disGubun, chgGubun) {
    let rtnList = [];

    switch (disGubun) {
        case 1:
            udc_pchsClnt.ilCommonPopUp(scwin.callbackPopUp1,
                cnd_ed_pchsClntNo.getValue().trim(),
                cnd_txt_pchsClntNm.getValue(),
                chgGubun,
                '5',
                'Customer',
                '140,300',
                null,
                null,
                '500',
                '500',
                null,
                null,
                null,
                'F',
                'Customer Search,Customer Code,Customer Name',
                'T');
            break;

        case 2:
            let pParam = ed_pchsClntNo.getValue().trim();
            if (pParam == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, ["Customer"]);
                ed_pchsClntNo.setFocus();
                return;
            }
            udc_pchsPic.ilCommonPopUp(scwin.callbackPopUp2,
                ed_pchsPicNo.getValue().trim(),
                txt_pchsPicNm.getValue(),
                chgGubun,
                '4',
                "PIC",
                '100,350',
                null,
                pParam,
                '500',
                '500',
                null,
                null,
                null,
                "T",
                null);
            break;

        case 3:
            udc_dept.ilCommonPopUp(scwin.callbackPopUp3,
                cnd_ed_dept.getValue().trim(),
                cnd_txt_deptnm.getValue(),
                "T",
                '2',
                "Code, Name",
                '80,230',
                "3,4,5,6,7,8,9,10",
                null,
                null,
                null,
                null,
                null,
                null,
                "F",
                "Department,Code,Name",
                "F");
            break;

        case 4:
            let pCode = ed_dept.getValue();
            let pName = "";
            udc_dept.ilCommonPopUp(scwin.callbackPopUp4,
                pCode,
                pName,
                "T",
                '2',
                "Code, Name",
                '80,230',
                "3,4,5,6,7,8,9,10",
                '',
                null,
                null,
                null,
                null,
                null,
                "F",
                "귀속부서,Code,Name",
                "T");
            break;

        default:
            break;
    }
};

scwin.callbackPopUp1 = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_pchsClntNo, cnd_txt_pchsClntNm);
};

scwin.callbackPopUp2 = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_pchsPicNo, txt_pchsPicNm, ed_pchsClntNo);
};

scwin.callbackPopUp3 = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, cnd_ed_dept, cnd_txt_deptnm);
};

scwin.callbackPopUp4 = async function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return;
        }
        scwin.hid_acctDeptCd = rtnList[4];
        scwin.hid_acctDeptNm = rtnList[1];
    } else {
        scwin.hid_acctDeptCd = "";
        scwin.hid_acctDeptNm = "";
    }
};

scwin.f_MhnoLoading = async function(mhgb, blno) {
    let strClntNo = blno;
    if (strClntNo.length > 0) {
        let param1 = strClntNo;
        let queryId = "";

        if (acb_seaair.getValue() == "A") {
            if (mhgb == "M") {
                queryId = "retriveAirMasterMhnoListCombo";
            } else {
                queryId = "retriveAirHouseMhnoListCombo";
            }
        } else if (acb_seaair.getValue() == "S") {
            if (mhgb == "M") {
                queryId = "retriveSeaMasterMhnoListCombo";
            } else {
                queryId = "retriveSeaHouseMhnoListCombo";
            }
        } else if (acb_seaair.getValue() == "T") {
            if (mhgb == "M") {
                await $c.win.alert("After House B/L No Input. Search Pls.");
                return;
            } else {
                queryId = "retriveTransMhnoListCombo";
            }
        }

        // TODO: ds_mhno 콤보 데이터 로딩 - 원본은 DataID URL 방식 사용. submission 또는 별도 API로 대체 필요.
        // 원본: ds_mhno.DataID = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=" + queryId + "&param1=" + param1 + "&param2=" + acb_iogb.getValue();
        // ds_mhno.Reset();
    }
};

scwin.sbm_mhno_submitdone = async function(e) {
    if (ds_mhno.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    } else {
        if (scwin.mblno != "" || scwin.blno != "") {
            scwin.f_Retrieve();
        }
    }
};

scwin.sbm_mhno_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_SlipCreate = async function() {
    let pchsDeptCd = ed_dept.getValue().trim();
    let pchsDeptNm = txt_deptnm.getValue().trim();

    let pchsClntNo = ed_pchsClntNo.getValue().trim();
    let pchsClntNm = txt_pchsClntNm.getValue().trim();

    let pchsIntendDtSt = ica_pchsIntendDt.getValue().trim();
    let pchsIntendDtEnd = ica_pchsIntendDt.getValue().trim();

    let row = ds_paymentInvoiceList.getRowPosition();
    let certiNo = "";
    if (row >= 0) {
        certiNo = ds_paymentInvoiceList.getCellData(row, "certiNo");
    }

    let ccChk = "0";
    let inuChk = "0";
    let k = 0;
    let l = 0;
    let m = 0;

    for (let i = 0; i < ds_purchaseCertiDetail.getRowCount(); i++) {
        if (ds_purchaseCertiDetail.getCellData(i, "fareEngCd") == "CCF") {
            k++;
        }
        if (ds_purchaseCertiDetail.getCellData(i, "fareEngCd") == "INU") {
            l++;
        }
        if (ds_purchaseCertiDetail.getCellData(i, "fareEngCd") != "INU") {
            m++;
        }
    }

    if (k > 0) {
        ccChk = "1";
    }

    if (l > 0 && m == 0) {
        inuChk = "1";
    }

    let paramObj = {
        pchsDeptCd: pchsDeptCd,
        pchsDeptNm: pchsDeptNm,
        pchsClntNo: pchsClntNo,
        pchsClntNm: pchsClntNm,
        certiNo: certiNo,
        pchsIntendDtSt: pchsIntendDtSt,
        pchsIntendDtEnd: pchsIntendDtEnd,
        ccChk: ccChk,
        inuChk: inuChk
    };

    $c.win.openMenu("세금계산서 접수 등록", "/ui/ds/fs/adjm/fs_103_01_01b.xml", "fs_103_01_01b.xml", paramObj);
};

