scwin.f_Slip = async function() {
    let pchsDeptCd = ed_dept.getValue().trim();
    let pchsDeptNm = txt_deptnm.getValue().trim();

    let pchsClntNo = ed_pchsClntNo.getValue().trim();
    let pchsClntNm = txt_pchsClntNm.getValue().trim();

    let pchsIntendDtSt = ica_pchsIntendDt.getValue().trim();
    let pchsIntendDtEnd = ica_pchsIntendDt.getValue().trim();

    let row = ds_paymentInvoiceList.getRowPosition();
    let certiNo = "";
    let prtnGrpNo = "";
    let cucd = "";
    let rate = "";
    let amtFcrc = "";
    let amt = "";
    let vat = "";

    if (row >= 0) {
        certiNo = ds_paymentInvoiceList.getCellData(row, "certiNo");
        prtnGrpNo = ds_paymentInvoiceList.getCellData(row, "prtnGrpNo");
        cucd = ds_paymentInvoiceList.getCellData(row, "cucd");
        rate = ds_paymentInvoiceList.getCellData(row, "rate");
        amtFcrc = ds_paymentInvoiceList.getCellData(row, "sumPchsAmtFcrc");
        amt = String(Number(ds_paymentInvoiceList.getCellData(row, "sumPchsAmt")) + Number(ds_paymentInvoiceList.getCellData(row, "sumVat")));
        vat = ds_paymentInvoiceList.getCellData(row, "sumVat");
    }

    if (certiNo == "" || prtnGrpNo == "") {
        await $c.win.alert("Payment Invoice를 먼저 생성 하세요");
        return;
    }

    if (ds_purchaseCertiDetail.getRowCount() < 1) {
        await $c.win.alert("상세 정보를 먼저 조회 하세요");
        return;
    }

    if (row >= 0 && ds_paymentInvoiceList.getCellData(row, "slipNo") != "") {
        await $c.win.alert("전표생성이 된 상태입니다.확인해 주십시오.");
        return;
    }

    let fareEngCd = ds_purchaseCertiDetail.getCellData(0, "fareEngCd");
    scwin.f_PopUp(4, 'T');

    let acctDeptCd = scwin.hid_acctDeptCd;
    let acctDeptNm = scwin.hid_acctDeptNm;
    let rmk = txa_rmk.getValue();

    let paramObj = {
        pchsDeptCd: pchsDeptCd,
        pchsDeptNm: pchsDeptNm,
        pchsClntNo: pchsClntNo,
        pchsClntNm: pchsClntNm,
        certiNo: certiNo,
        prtnGrpNo: prtnGrpNo,
        fareEngCd: fareEngCd,
        pchsIntendDtSt: pchsIntendDtSt,
        pchsIntendDtEnd: pchsIntendDtEnd,
        cucd: cucd,
        rate: rate,
        amtFcrc: amtFcrc,
        amt: amt,
        vat: vat,
        acctDeptCd: acctDeptCd,
        acctDeptCd2: pchsDeptCd,
        acctDeptNm: acctDeptNm,
        rmk: rmk
    };

    $c.win.openMenu("대납금 전표 생성", "/ui/il/acc/acpay/ac_106_01_04b.xml", "ac_106_01_04b.xml", paramObj);
};

