scwin.ds_paymentInvoiceList_onrowpositionchange = function(info) {
    let row = ds_paymentInvoiceList.getRowPosition();
    let vRowStatus = "";
    if (row >= 0) {
        vRowStatus = ds_paymentInvoiceList.getRowStatus(row);
    }

    if (row >= 0) {
        let vCountRow = ds_paymentInvoiceList.getRowCount();
        let vChgCount = 0;
        let vChgRow = 0;

        for (let i = 0; i < vCountRow; i++) {
            let vCurRowStatus = ds_paymentInvoiceList.getRowStatus(i);
            if (vCurRowStatus == "C" || vCurRowStatus == "U") {
                vChgCount++;
                vChgRow = i;
            }
        }

        if (vChgCount > 0 && row != vChgRow) {
            alert("프로그램 신규등록이나 수정사항을 저장하신 후에 다른 프로그램정보로 이동해주시기 바랍니다.");
            ds_paymentInvoiceList.setRowPosition(vChgRow);
            return;
        }

        let kcomcd = ds_paymentInvoiceList.getCellData(row, "kcomcd");
        let seaair = ds_paymentInvoiceList.getCellData(row, "seaair");
        let iogb = ds_paymentInvoiceList.getCellData(row, "iogb");
        let mblno = ds_paymentInvoiceList.getCellData(row, "mblno");
        let blno = ds_paymentInvoiceList.getCellData(row, "blno");
        let mhno = ds_paymentInvoiceList.getCellData(row, "mhno");

        let certiNo = ds_paymentInvoiceList.getCellData(row, "certiNo");
        let prtnGrpNo = ds_paymentInvoiceList.getCellData(row, "prtnGrpNo");
        let pchsClntNo = ds_paymentInvoiceList.getCellData(row, "pchsClntNo");
        let pchsClntNm = ds_paymentInvoiceList.getCellData(row, "pchsClntNm");

        let slipNo = ds_paymentInvoiceList.getCellData(row, "slipNo");
        let odrNo = ds_paymentInvoiceList.getCellData(row, "odrNo");

        let dvgb = ds_paymentInvoiceList.getCellData(row, "dvgb");

        let intendDt = ds_paymentInvoiceList.getCellData(row, "pchsIntendDt");
        let pchsPicNo = ds_paymentInvoiceList.getCellData(row, "pchsPicNo");
        let pchsPicNm = ds_paymentInvoiceList.getCellData(row, "pchsPicNm");

        ds_searchFreight.set("kcomcd", kcomcd);
        ds_searchFreight.set("seaair", seaair);
        ds_searchFreight.set("iogb", iogb);
        ds_searchFreight.set("mblno", mblno);
        ds_searchFreight.set("blno", blno);
        ds_searchFreight.set("mhno", mhno);

        ds_searchFreight.set("certiNo", certiNo);
        ds_searchFreight.set("prtnGrpNo", prtnGrpNo);
        ds_searchFreight.set("bilgClntNo", pchsClntNo);
        ds_searchFreight.set("bilgClntNm", pchsClntNm);
        ds_searchFreight.set("dvgb", dvgb);

        ds_searchFreight.set("odrNo", odrNo);
        ds_searchFreight.set("slipNo", slipNo);

        scwin.hid_intendDt = intendDt;
        scwin.hid_pchsPicNo = pchsPicNo;
        scwin.hid_pchsPicNm = pchsPicNm;

        if (vRowStatus == "R") {
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Cancel, btn_Save, btn_Delete, rd_billgb]);
            if (prtnGrpNo.trim() == "") {
                $c.gus.cfEnableBtnOnly([btn_Create, rd_billgb]);
                scwin.processFlag = "INIT";
            } else {
                $c.gus.cfDisableObjects([rd_billgb]);
                if (slipNo == "") {
                    $c.gus.cfEnableBtnOnly([btn_Update, btn_Delete]);
                    scwin.processFlag = "RETRIEVE";
                } else {
                    scwin.processFlag = "INIT";
                }
            }
        } else if (vRowStatus == "C") {
            scwin.f_Set("CREATE");
        } else if (vRowStatus == "U") {
            scwin.f_Set("UPDATE");
        }
    } else {
        scwin.f_Set("INIT");
        scwin.processFlag = "INIT";
    }
};

scwin.ds_paymentInvoiceList_oncelldatachange = function(info) {
    let row = info.row;
    let colid = info.colId;

    if (ds_paymentInvoiceList.getRowCount() > 0) {
        switch (colid) {
            case "confirmDt":
                let confirmDt = ds_paymentInvoiceList.getCellData(row, "confirmDt");
                for (let i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
                    ds_purchaseCerti.setCellData(i, "pchsIntendDt", confirmDt);
                }
                break;

            case "pchsPicNo":
                let pchsPicNo = ed_pchsPicNo.getValue();
                let pchsPicNm = txt_pchsPicNm.getValue();
                for (let i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
                    ds_purchaseCerti.setCellData(i, "pchsPicNo", pchsPicNo);
                    ds_purchaseCerti.setCellData(i, "pchsPicNm", pchsPicNm);
                }
                break;

            case "clntBilgDocNo":
                let clntBilgDocNo = ds_paymentInvoiceList.getCellData(row, "clntBilgDocNo");
                for (let i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
                    ds_purchaseCerti.setCellData(i, "clntBilgDocNo", clntBilgDocNo);
                }
                break;

            default:
                break;
        }
    }
};

scwin.ds_purchaseCertiDetail_onrowpositionchange = function(info) {
    let row = ds_purchaseCertiDetail.getRowPosition();
    if (row >= 0) {
        if (ds_purchaseCertiDetail.getCellData(row, "certiNo") == "") {
            gr_paymentInvoiceFreightList.setColumnProp("chk", "readOnly", false);
        } else {
            gr_paymentInvoiceFreightList.setColumnProp("chk", "readOnly", true);
        }
    } else {
        gr_paymentInvoiceFreightList.setColumnProp("chk", "readOnly", true);
    }
};

scwin.ds_purchaseCertiDetail_oncelldatachange = function(info) {
    let row = info.row;
    let colid = info.colId;

    let vatCnt = 0;
    let pchsAmt = 0;
    let pchsAmtFcrc = 0;
    let vat = 0;

    if (ds_purchaseCertiDetail.getRowCount() > 0) {
        if (colid == "chk") {
            let refkey = ds_purchaseCertiDetail.getCellData(row, "refkey");

            pchsAmt = ds_purchaseCertiDetail.getCellData(row, "pchsAmt");
            pchsAmtFcrc = ds_purchaseCertiDetail.getCellData(row, "pchsAmtFcrc");
            vat = ds_purchaseCertiDetail.getCellData(row, "vat");

            pchsAmt = pchsAmt * (Math.pow(10, 0)) / (Math.pow(10, 0));
            pchsAmtFcrc = pchsAmtFcrc * (Math.pow(10, 2)) / (Math.pow(10, 2));
            vat = vat * (Math.pow(10, 0)) / (Math.pow(10, 0));

            if (ds_purchaseCertiDetail.getCellData(row, "chk") == "T") {
                for (let i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
                    if (refkey == ds_purchaseCerti.getCellData(i, "refkey")) {
                        ds_purchaseCerti.setCellData(i, "pchsAmt", (parseFloat(ds_purchaseCerti.getCellData(i, "pchsAmt")) + parseFloat(pchsAmt)) * (Math.pow(10, 0)) / (Math.pow(10, 0)));
                        ds_purchaseCerti.setCellData(i, "pchsAmtFcrc", (parseFloat(ds_purchaseCerti.getCellData(i, "pchsAmtFcrc")) + parseFloat(pchsAmtFcrc)) * (Math.pow(10, 2)) / (Math.pow(10, 2)));
                        ds_purchaseCerti.setCellData(i, "vat", (parseFloat(ds_purchaseCerti.getCellData(i, "vat")) + parseFloat(vat)) * (Math.pow(10, 0)) / (Math.pow(10, 0)));
                    }
                }
            } else {
                for (let i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
                    if (refkey == ds_purchaseCerti.getCellData(i, "refkey")) {
                        ds_purchaseCerti.setCellData(i, "pchsAmt", (parseFloat(ds_purchaseCerti.getCellData(i, "pchsAmt")) - parseFloat(pchsAmt)) * (Math.pow(10, 0)) / (Math.pow(10, 0)));
                        ds_purchaseCerti.setCellData(i, "pchsAmtFcrc", (parseFloat(ds_purchaseCerti.getCellData(i, "pchsAmtFcrc")) - parseFloat(pchsAmtFcrc)) * (Math.pow(10, 3)) / (Math.pow(10, 3)));
                        ds_purchaseCerti.setCellData(i, "vat", (parseFloat(ds_purchaseCerti.getCellData(i, "vat")) - parseFloat(vat)) * (Math.pow(10, 0)) / (Math.pow(10, 0)));
                    }
                }
            }

            for (let i = 0; i < ds_purchaseCertiDetail.getRowCount(); i++) {
                if (ds_purchaseCertiDetail.getCellData(i, "chk") == "T" && refkey == ds_purchaseCertiDetail.getCellData(i, "refkey")) {
                    vatCnt = vatCnt + 1;
                }
            }

            if (vatCnt < 1) {
                for (let i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
                    if (ds_purchaseCerti.getCellData(i, "chk") == "T" && refkey == ds_purchaseCerti.getCellData(i, "refkey")) {
                        ds_purchaseCerti.setCellData(i, "chk", "F");
                    }
                }
            } else {
                for (let i = 0; i < ds_purchaseCerti.getRowCount(); i++) {
                    if (ds_purchaseCerti.getCellData(i, "chk") == "F" && refkey == ds_purchaseCerti.getCellData(i, "refkey")) {
                        ds_purchaseCerti.setCellData(i, "chk", "T");
                    }
                }
            }
        }
    }
};

scwin.gr_paymentInvoiceFreightList_onheaderclick = function(headerIndex, columnIndex, columnId) {
    if (columnId == "chk") {
        let cr = ds_purchaseCertiDetail.getRowCount();
        if (cr > 0) {
            for (let i = 0; i < cr; i++) {
                if (ds_purchaseCertiDetail.getCellData(i, "chk") == "F") {
                    ds_purchaseCertiDetail.setCellData(i, "chk", "T");
                }
            }
        }
    }
};
